import React, { useState, useEffect } from "react";
import axios from "axios";

function Dashboard() {
    const [file, setFile] = useState(null);
    const [resumes, setResumes] = useState([]);
    const [result, setResult] = useState([]);
    const [searchSkill, setSearchSkill] = useState("");
    const [searchExp, setSearchExp] = useState("");

    const [editingResume, setEditingResume] = useState(null);
    const [editForm, setEditForm] = useState({
        name: "",
        email: "",
        skills: "",
        experience: 0
    });

    const token = localStorage.getItem("token");

    // ✅ Fetch resumes
    useEffect(() => {
        fetchResumes();
    }, []);

    const fetchResumes = async () => {
        try {
            const res = await axios.get("http://localhost:8080/resumes", {
                headers: { Authorization: `Bearer ${token}` }
            });
            setResumes(res.data);
        } catch (err) {
            console.error(err);
        }
    };

    // ✅ Upload
    const handleUpload = async () => {
        if (!file) return alert("Select file first");

        const formData = new FormData();
        formData.append("file", file);
        formData.append("name", "Test User");
        formData.append("email", "test@gmail.com");
        formData.append("skills", "java spring boot");
        formData.append("experience", 2);

        try {
            await axios.post(
                "http://localhost:8080/resumes/upload",
                formData,
                {
                    headers: {
                        Authorization: `Bearer ${token}`,
                        "Content-Type": "multipart/form-data"
                    }
                }
            );

            alert("Uploaded!");
            fetchResumes();
        } catch (err) {
            console.error(err);
        }
    };

    // ✅ Delete
    const handleDelete = async (id) => {
        try {
            await axios.delete(`http://localhost:8080/resumes/${id}`, {
                headers: { Authorization: `Bearer ${token}` }
            });

            alert("Deleted!");
            fetchResumes();
        } catch (err) {
            console.error(err);
        }
    };

    // ✅ Download
    const handleDownload = async (id) => {
        try {
            const res = await axios.get(
                `http://localhost:8080/resumes/download/${id}`,
                {
                    headers: { Authorization: `Bearer ${token}` },
                    responseType: "blob"
                }
            );

            const url = window.URL.createObjectURL(new Blob([res.data]));
            const link = document.createElement("a");
            link.href = url;
            link.setAttribute("download", "resume.pdf");
            document.body.appendChild(link);
            link.click();
        } catch (err) {
            console.error(err);
        }
    };

    // ✅ Start Edit
    const startEdit = (resume) => {
        setEditingResume(resume);
        setEditForm({
            name: resume.name,
            email: resume.email,
            skills: resume.skills,
            experience: resume.experience
        });
    };

    // ✅ Update
    const handleUpdate = async () => {
        try {
            await axios.put(
                `http://localhost:8080/resumes/${editingResume.id}`,
                editForm,
                {
                    headers: { Authorization: `Bearer ${token}` }
                }
            );

            alert("Updated!");
            setEditingResume(null);
            fetchResumes();
        } catch (err) {
            console.error(err);
        }
    };

    // ✅ Match
    const getMatches = async () => {
        try {
            const res = await axios.get(
                "http://localhost:8080/resumes/match?skill=java&experience=1",
                {
                    headers: { Authorization: `Bearer ${token}` }
                }
            );
            setResult(res.data);
        } catch (err) {
            console.error(err);
        }
    };

    // ✅ Logout
    const handleLogout = () => {
        localStorage.removeItem("token");
        window.location.reload();
    };

    return (
        <div style={{ padding: 20 }}>
            <h2>Dashboard</h2>

            <button onClick={handleLogout}>Logout</button>

            <hr />

            {/* 🔥 EDIT FORM */}
            {editingResume && (
                <div style={{ border: "1px solid black", padding: 15 }}>
                    <h3>Edit Resume</h3>

                    <input
                        value={editForm.name}
                        onChange={(e) =>
                            setEditForm({ ...editForm, name: e.target.value })
                        }
                        placeholder="Name"
                    /><br /><br />

                    <input
                        value={editForm.email}
                        onChange={(e) =>
                            setEditForm({ ...editForm, email: e.target.value })
                        }
                        placeholder="Email"
                    /><br /><br />

                    <input
                        value={editForm.skills}
                        onChange={(e) =>
                            setEditForm({ ...editForm, skills: e.target.value })
                        }
                        placeholder="Skills"
                    /><br /><br />

                    <input
                        type="number"
                        value={editForm.experience}
                        onChange={(e) =>
                            setEditForm({ ...editForm, experience: e.target.value })
                        }
                    /><br /><br />

                    <button onClick={handleUpdate}>Update</button>
                    <button onClick={() => setEditingResume(null)}>Cancel</button>
                </div>
            )}

            <hr />

            {/* 🔥 UPLOAD */}
            <h3>Add Resume</h3>
            <input type="file" onChange={(e) => setFile(e.target.files[0])} />
            <br /><br />
            <button onClick={handleUpload}>Upload</button>

            <hr />

            {/* 🔥 LIST */}
            <h3>Search Resumes</h3>

            <input
                placeholder="Skill (e.g. java)"
                value={searchSkill}
                onChange={(e) => setSearchSkill(e.target.value)}
            />

            <input
                type="number"
                placeholder="Min Experience"
                value={searchExp}
                onChange={(e) => setSearchExp(e.target.value)}
            />

            <button onClick={handleSearch}>Search</button>
            <h3>Your Resumes</h3>

            {resumes.length === 0 ? (
                <p>No resumes</p>
            ) : (
                <ul>
                    {resumes.map((r) => (
                        <li key={r.id}>
                            <b>{r.name}</b> - {r.skills} ({r.experience} yrs)
                            <br />
                            <button onClick={() => startEdit(r)}>Edit</button>
                            <button onClick={() => handleDownload(r.id)}>Download</button>
                            <button onClick={() => handleDelete(r.id)}>Delete</button>
                        </li>
                    ))}
                </ul>
            )}

            <hr />

            {/* 🔥 MATCH */}
            <h3>Find Matches</h3>
            <button onClick={getMatches}>Find Matches</button>

            <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 20 }}>
                {result.map((r, i) => (
                    <div key={i} style={{ border: "1px solid #ccc", padding: 10 }}>
                        <h4>{r.summary?.name}</h4>
                        <p>{r.summary?.skills}</p>
                        <p>Score: {r.score}</p>

                        <button onClick={() => handleDownload(r.summary.id)}>
                            Download
                        </button>
                    </div>
                ))}
            </div>
        </div>
    );
}

export default Dashboard;
